using EnergyModel

module GHG_MacroEconomy_US

import ...EnergyModel: ReadDisk,WriteDisk,Select
import ...EnergyModel: HisTime,ITime,MaxTime,First,Future,Final,Yr
import ...EnergyModel: @finite_math,finite_inverse,finite_divide,finite_power,finite_exp,finite_log
import ...EnergyModel: DB

const VariableArray{N} = Array{Float32,N} where {N}
const SetArray = Vector{String}

Base.@kwdef struct MControl
  db::String

  Area::SetArray = ReadDisk(db,"MainDB/AreaKey")
  AreaDS::SetArray = ReadDisk(db,"MainDB/AreaDS")
  Areas::Vector{Int} = collect(Select(Area))
  ECC::SetArray = ReadDisk(db,"MainDB/ECCKey")
  ECCDS::SetArray = ReadDisk(db,"MainDB/ECCDS")
  ECCs::Vector{Int} = collect(Select(ECC))
  Nation::SetArray = ReadDisk(db,"MainDB/NationKey")
  NationDS::SetArray = ReadDisk(db,"MainDB/NationDS")
  Nations::Vector{Int} = collect(Select(Nation))
  Poll::SetArray = ReadDisk(db,"MainDB/PollKey")
  PollDS::SetArray = ReadDisk(db,"MainDB/PollDS")
  Polls::Vector{Int} = collect(Select(Poll))
  Year::SetArray = ReadDisk(db,"MainDB/YearKey")
  YearDS::SetArray = ReadDisk(db,"MainDB/YearDS")
  Years::Vector{Int} = collect(Select(Year))

  ANMap::VariableArray{2} = ReadDisk(db,"MainDB/ANMap") # [Area,Nation] Map between Area and Nation
  MEDriver::VariableArray{3} = ReadDisk(db,"MOutput/MEDriver") # [ECC,Area,Year] Driver for Process Emissions (Various Millions/Yr)
  MEPOCX::VariableArray{4} = ReadDisk(db,"MEInput/MEPOCX") # [ECC,Poll,Area,Year] Process Pollution Coefficient (Tonnes/$B-Output)
  PolConv::VariableArray{1} = ReadDisk(db,"SInput/PolConv") # [Poll] Pollution Conversion Factor (convert GHGs to eCO2)
  xMEPol::VariableArray{4} = ReadDisk(db,"SInput/xMEPol") # [ECC,Poll,Area,Year] Process Pollution (Tonnes/Yr)
  
  #
  # Scratch Sets
  #
  EPAInd::SetArray = ["Adipic Acid Production","Aluminum Production","Ammonia Production & Urea Consumption","Carbon Dioxide Consumption","Cement Manufacture","Electrical Transmission and Distribution","Ferroalloy Production","HCFC-22 Production","Iron and Steel Production & Metallurgic Coke Pro","Lead Production","Lime Production","Limestone and Dolomite Use","Magnesium Production and Processing","Nitric Acid Production","Petrochemical Production","Phosphoric Acid Production","Semiconductor Manufacturing HFCs","Semiconductor Manufacturing PFCs","Semiconductor Manufacturing SF6","Silicon Carbide Production","Silicon Carbide Consumption","Soda Ash Production","Soda Ash Consumption","Substitution of Ozone Depleting Substances","Titanium Dioxide Production","Zinc Production","Solvent and Other Product Use","Agriculture","Land Use","Landfills","Wastewater Treatment","Composting"]        # EPA Industries
  EPAInds::Vector{Int} = collect(Select(EPAInd))
  
  #
  # Scratch Variables
  #
  Data::VariableArray{1} = zeros(Float32,length(Year)) # [Year] Emissions by Input Year
  EPACoef::VariableArray{3} = zeros(Float32,length(EPAInd),length(Poll),length(Year)) # [EPAInd,Poll,Year] Non-Energy Pollution Coefficient by EPA Industries (Tonnes/$B-output)
  EPAEcMap::VariableArray{2} = zeros(Float32,length(EPAInd),length(ECC))
  EPAPol::VariableArray{3} = zeros(Float32,length(EPAInd),length(Poll),length(Year)) # [EPAInd,Poll,Year] Emissions by EPA Industry (Tg CO2 Eq.)
  NXMEPol::VariableArray{3} = zeros(Float32,length(ECC),length(Poll),length(Year)) # [ECC,Poll,Year] National Emissions (eCO2 Tonnes)
  xDrNat::VariableArray{2} = zeros(Float32,length(ECC),length(Year)) # [ECC,Year] National Driver (TBTu/Yr)
end

function ReadUSEmissions(data,poll,epaind,temp_data)
  (;Data,EPAPol) = data

  # 
  # Data is currently available from 1990 to 2008 Ian 10/15/10
  # 
  Data[Yr(1990):Yr(2008)] = temp_data

  for year in Yr(1990):Yr(2008)
    EPAPol[epaind,poll,year] = EPAPol[epaind,poll,year]+Data[year]
  end

end

