  # 
  # This procedure reads in U.S. Non-Energy Emissions by EPA industry
  # and calculates MEPOCX based on process emissions driver (MEDriver).
  # 
  US = Select(Nation,"US")
  us_areas = Select(ANMap[Areas,US],==(1.0))
  polls = Select(Poll,["CO2","CH4","N2O","SF6","PFC","HFC"])

  EPAPol[EPAInds,polls,Years] .= 0.0
  xMEPol[ECCs,polls,us_areas,Years] .= 0.0
  MEPOCX[ECCs,polls,us_areas,Years] .= 0.0

  # 
  # US national Driver
  # 
  for ecc in ECCs, year in Years
    xDrNat[ecc,year] = sum(MEDriver[ecc,area,year] for area in us_areas)
  end


