  ReadUSEmissions(data,Select(Poll,"HFC"),Select(EPAInd,"Substitution of Ozone Depleting Substances"),        [  0.3,      0.6,      1.7,      5.5,     12.5,       29,     40.3,     51.3,     58.7,     66.5,     74.3,     80.3,     86.4,     92.2,     98.2,    103.2,    107.7,    110.1,      113]) 
  ReadUSEmissions(data,Select(Poll,"HFC"),Select(EPAInd,"HCFC-22 Production"),                                [ 36.4,     32.7,     36.4,     33.1,     31.5,       33,     31.2,     30.1,     39.5,     30.4,     28.6,     19.7,     21.1,     12.3,     17.2,     15.8,     13.8,       17,     13.6]) 
