  ReadUSEmissions(data,Select(Poll,"SF6"),Select(EPAInd,"Semiconductor Manufacturing SF6"),                   [  0.5,      0.5,      0.5,      0.6,      0.7,      0.9,        1,      1.1,      1.3,      1.3,      1.1,      0.7,      0.7,      0.8,      0.8,        1,        1,      0.8,      1.1]) 
  ReadUSEmissions(data,Select(Poll,"SF6"),Select(EPAInd,"Magnesium Production and Processing"),               [  5.4,      5.2,      5.5,      5.6,      5.4,      5.6,      6.6,      6.4,      5.9,      5.9,        3,      2.9,      2.9,      3.4,      2.9,      2.9,      2.9,      2.6,        2]) 
  ReadUSEmissions(data,Select(Poll,"SF6"),Select(EPAInd,"Electrical Transmission and Distribution"),          [ 26.6,     25.5,     25.4,     24.6,     23.2,     21.4,     19.6,     17.9,     15.3,     15.6,       15,     15.1,     14.5,       14,     13.9,       14,     13.2,     12.7,     13.1]) 

  #
  #  Convert emissions from MT eCO2 to Tonnes of pollutants
  # 
  for epaind in EPAInds, poll in Polls, year in Years
    @finite_math EPAPol[epaind,poll,year] = EPAPol[epaind,poll,year]*1E6/PolConv[poll]
  end

  # 
  # Loop through EPA industries
  # 
  NXMEPol .= 0

  for epaind in EPAInds
    # 
    # Select ECCs associated with given EPA industry (EPAEcMap)
    # 
    # eccs = Select(EPAEcMap[epaind,ECCs],==(1.0))
    eccs = findall(EPAEcMap[epaind,ECCs] .== 1.0)
    if eccs != []
      for poll in Polls, year in Years

        # 
        # Calculate coefficient for each EPA Industry
        # 
        @finite_math EPACoef[epaind,poll,year] = EPAPol[epaind,poll,year]/sum(xDrNat[ecc,year] for ecc in eccs)

        # 
        # Accumulate total emissions for each ECC
        # 
        for ecc in eccs
          NXMEPol[ecc,poll,year] = NXMEPol[ecc,poll,year] + (EPACoef[epaind,poll,year]*xDrNat[ecc,year])
        end
      end
    end
  end

  # 
  # Calculate coefficient for each ECC. xMEPol is stored in area WS, but applies to total US. 
  # 
  for ecc in ECCs, poll in Polls, area in us_areas, year in Years
    @finite_math MEPOCX[ecc,poll,area,year] = NXMEPol[ecc,poll,year]/xDrNat[ecc,year]
  end

  # 
  # Hold values constant after 2008
  # 
  for ecc in ECCs, poll in Polls, area in us_areas, year in Yr(2009):Final
    MEPOCX[ecc,poll,area,year] = MEPOCX[ecc,poll,area,Yr(2008)] 
  end

  # 
  # Estimate Process Emissions
  # 
  for ecc in ECCs, poll in Polls, area in us_areas, year in Years
    xMEPol[ecc,poll,area,year] = MEPOCX[ecc,poll,area,year]*MEDriver[ecc,area,year]
  end

  WriteDisk(db,"MEInput/MEPOCX",MEPOCX)
  WriteDisk(db,"SInput/xMEPol",xMEPol)

end

function CalibrationControl(db)
  @info "GHG_MacroEconomy_US.jl - CalibrationControl"

  MCalibration(db)

end

if abspath(PROGRAM_FILE) == @__FILE__
  CalibrationControl(DB)
end

